import React, { useState } from 'react';

const ANOS = [2026, 2025, 2024];
const MESES = [
  'Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho',
  'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'
];

const initialData = () => {
  const data = {};
  ANOS.forEach(ano => {
    data[ano] = {};
    MESES.forEach(mes => {
      data[ano][mes] = {
        checked: false,
        file: null,
        fileUrl: '',
      };
    });
  });
  return data;
};

export default function AcompanhamentoSCM({ razaoSocial }) {
  const [dados, setDados] = useState(initialData());

  const handleCheck = (ano, mes) => {
    setDados(prev => ({
      ...prev,
      [ano]: {
        ...prev[ano],
        [mes]: {
          ...prev[ano][mes],
          checked: !prev[ano][mes].checked
        }
      }
    }));
  };

  const handleFileChange = (ano, mes, e) => {
    const file = e.target.files[0];
    if (file) {
      // Monta o nome: COMP_SCM_RAZAOSOCIAL_ANO_MES.pdf
      const nomeLimpo = (razaoSocial || "").normalize('NFD').replace(/[^\w\s]/gi, '').replace(/\s+/g, '_').toUpperCase();
      const nomeArquivo = `COMP_SCM_${nomeLimpo}_${ano}_${mes.toUpperCase()}.pdf`;
      const novoFile = new File([file], nomeArquivo, { type: file.type });
      const url = URL.createObjectURL(novoFile);
      setDados(prev => ({
        ...prev,
        [ano]: {
          ...prev[ano],
          [mes]: {
            ...prev[ano][mes],
            file: novoFile,
            fileUrl: url
          }
        }
      }));
    }
  };

  const handleDownload = (ano, mes) => {
    const { file, fileUrl } = dados[ano][mes];
    if (file && fileUrl) {
      const link = document.createElement('a');
      link.href = fileUrl;
      link.download = file.name;
      link.click();
    }
  };

  return (
    <div style={{ padding: 24 }}>
      <h2 style={{ textAlign: 'center', marginBottom: 24 }}>Acompanhamento SCM</h2>
      {ANOS.map(ano => (
        <div key={ano} style={{ marginBottom: 32, border: '1px solid #1976d2', borderRadius: 12, background: '#f4f8ff', boxShadow: '0 2px 8px #0001', padding: 16 }}>
          <h3 style={{ color: '#1976d2', marginBottom: 12 }}>{ano}</h3>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
            {MESES.map(mes => (
              <div key={mes} style={{ minWidth: 220, background: '#fff', borderRadius: 8, boxShadow: '0 1px 4px #0001', padding: 12, marginBottom: 8, display: 'flex', flexDirection: 'column', alignItems: 'flex-start', border: dados[ano][mes].checked ? '2px solid #388e3c' : '1px solid #ccc' }}>
                <label style={{ fontWeight: 600, marginBottom: 4 }}>
                  <input type="checkbox" checked={dados[ano][mes].checked} onChange={() => handleCheck(ano, mes)} style={{ marginRight: 8 }} />
                  {mes}
                </label>
                <div style={{display:'flex', alignItems:'center', gap:8, marginBottom:8}}>
                  <input type="file" accept="application/pdf" onChange={e => handleFileChange(ano, mes, e)} />
                  {dados[ano][mes].file && (
                    <span style={{fontSize:13, color:'#1976d2', fontWeight:500}}>{dados[ano][mes].file.name}</span>
                  )}
                </div>
                {dados[ano][mes].file && (
                  <button onClick={() => handleDownload(ano, mes)} style={{ background: '#1976d2', color: '#fff', border: 'none', borderRadius: 4, padding: '4px 12px', fontWeight: 600, cursor: 'pointer' }}>
                    Download
                  </button>
                )}
              </div>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
}
